if (maxWithdraw) {
  // First attempt to redeem all cDai from Compound if there is a balance.
  _withdrawMaxFromCompound(AssetType.DAI);

  // Then transfer all Dai to recipient if there is a balance.
  require(_transferMax(_DAI, recipient, false));
  success = true;
} else {
  // Attempt to withdraw specified Dai from Compound before proceeding.
  if (_withdrawFromCompound(AssetType.DAI, amount)) {
    // At this point Dai transfer should never fail - wrap it just in case.
    require(_DAI.transfer(recipient, amount));
    success = true;
  }
}

if (transferAmount > 0) {
  if (!suppressRevert) {
    // Perform the transfer and pass along the returned boolean (or revert).
    success = token.transfer(recipient, transferAmount);
  } else {
    // Attempt transfer with 1/2 gas, allow reverts, and return call status.
    (success, ) = address(token).call.gas(gasleft() / 2)(
      abi.encodeWithSelector(
        token.transfer.selector, recipient, transferAmount
      )
    );
  }
} else {
  // Skip the transfer and return true.
  success = true;
}

if (!suppressRevert) {
  balance = token.balanceOf(address(this));
} else {
  // Try to retrieve current token balance for this account with 1/2 gas.
  (bool ok, bytes memory data) = address(token).call.gas(gasleft() / 2)(
    abi.encodeWithSelector(token.balanceOf.selector, address(this))
  );

  if (ok && data.length == 32) {
    balance = abi.decode(data, (uint256));
  } else {
    // Something went wrong with the balance check.
    balanceCheckWorked = false;
  }
}

assembly {
  // retrieve the size of the external code
  let size := extcodesize(target)

  // allocate output byte array
  codeValue := mload(0x40)

  // new "memory end" including padding
  mstore(0x40, add(codeValue, and(add(size, 0x3f), not(0x1f))))

  // store length in memory
  mstore(codeValue, size)

  // get the code using extcodecopy
  extcodecopy(target, add(codeValue, 0x20), 0, size)
}

unchecked {
    result = (result + x / result) >> 1;
    result = (result + x / result) >> 1;
    result = (result + x / result) >> 1;
    result = (result + x / result) >> 1;
    result = (result + x / result) >> 1;
    result = (result + x / result) >> 1;
    result = (result + x / result) >> 1;

    // If x is not a perfect square, round the result toward zero.
    uint256 roundedResult = x / result;
    if (result >= roundedResult) {
        result = roundedResult;
    }
}

assembly {
    extraData := extraData // Silence unused variable compiler warning.
    let m := mload(0x40) // Grab the free memory pointer.
    calldatacopy(m, data.offset, data.length)
    if iszero(call(gas(), to, value, m, data.length, codesize(), 0x00)) {
        // Bubble up the revert if the call reverts.
        returndatacopy(m, 0x00, returndatasize())
        revert(m, returndatasize())
    }
}
